use crate::ast_types::{BridgeExpression, BridgeNodePlan, BridgeOperation};
use crate::compiler::CompileState;
use crate::polyglot_traits::{PolyglotExpression, PolyglotFunction, PolyglotStatement};

fn compile_polyglot_expression(expr: &PolyglotExpression) -> Result<BridgeExpression, String> {
    match expr {
        PolyglotExpression::Identifier(name) => {
            // Usually we might need to verify known bindings but a generic polyglot parser
            // may delay resolving bindings until runtime.
            // For now, assume it's a runtime identifier if it's not known.
            Ok(BridgeExpression::Runtime { ghost_mass: None,  name: name.clone() })
        }
        PolyglotExpression::Literal(value) => {
            Ok(BridgeExpression::Literal { ghost_mass: None,  value: value.clone() })
        }
        PolyglotExpression::Member { target, property } => {
            let compiled_target = compile_polyglot_expression(target)?;
            Ok(BridgeExpression::Member { ghost_mass: None, 
                target: Box::new(compiled_target),
                property: property.clone(),
            })
        }
        PolyglotExpression::Call { callee: _, args: _ } => {
            // A nested call expression that we might need to map to a node plan
            // Note: In strict Betti topology, nested calls are lifted to top-level node plans.
            // But BridgeExpression doesn't natively support nested calls unless extracted statically.
            Err("Nested function calls unsupported in pure polyglot expression resolution".to_string())
        }
    }
}

pub fn compile_polyglot_statement(
    stmt: &PolyglotStatement,
    state: &mut CompileState,
) -> Result<(), String> {
    match stmt {
        PolyglotStatement::VariableDeclaration { bindings, init } => {
            if bindings.is_empty() {
                return Err("Variable declaration requires at least one binding".to_string());
            }
            let binding_name = bindings[0].clone();

            if let Some(init_expr) = init {
                if let PolyglotExpression::Call { callee, args } = init_expr {
                    // It's a call expression mapped to a variable.
                    let callee_expr = compile_polyglot_expression(callee)?;
                    let mut compiled_args = Vec::new();
                    for arg in args {
                        compiled_args.push(compile_polyglot_expression(arg)?);
                    }

                    let node_id = state.create_node_id("call", &binding_name);
                    let plan = BridgeNodePlan::Call { ghost_mass: None, 
                        node_id,
                        handler_label: "PolyglotBridgeCall".to_string(),
                        callee: callee_expr,
                        this_arg: None, // Polyglot doesn't deeply model "this" out of the box
                        args: compiled_args,
                        assign_to: Some(binding_name.clone()),
                        source_location: None,
                    };
                    state.known_bindings.insert(binding_name);
                    state.node_plans.push(plan.clone());
                    state.operations.push(BridgeOperation::Call { plan });
                    return Ok(());
                }

                let assign_node_id = state.create_node_id("assign", &binding_name);
                let assign_plan = BridgeNodePlan::Assign { ghost_mass: None, 
                    node_id: assign_node_id,
                    handler_label: "PolyglotBridgeAssign".to_string(),
                    binding_name: binding_name.clone(),
                    expression: compile_polyglot_expression(init_expr)?,
                    source_location: None,
                };
                
                state.known_bindings.insert(binding_name);
                state.node_plans.push(assign_plan.clone());
                state.operations.push(BridgeOperation::Assign { plan: assign_plan });
            }
            Ok(())
        }
        PolyglotStatement::Return(opt_expr) => {
            if let Some(expr) = opt_expr {
                if let PolyglotExpression::Call { callee, args } = expr {
                    let return_binding = state.create_temp_binding("return");
                    
                    let callee_expr = compile_polyglot_expression(callee)?;
                    let mut compiled_args = Vec::new();
                    for arg in args {
                        compiled_args.push(compile_polyglot_expression(arg)?);
                    }
                    
                    let call_node_id = state.create_node_id("call", "return_call");
                    let call_plan = BridgeNodePlan::Call { ghost_mass: None, 
                        node_id: call_node_id,
                        handler_label: "PolyglotBridgeCall".to_string(),
                        callee: callee_expr,
                        this_arg: None,
                        args: compiled_args,
                        assign_to: Some(return_binding.clone()),
                        source_location: None,
                    };
                    state.operations.push(BridgeOperation::Call { plan: call_plan });

                    let ret_node_id = state.create_node_id("return", "result");
                    let ret_plan = BridgeNodePlan::Return { ghost_mass: None, 
                        node_id: ret_node_id,
                        handler_label: "PolyglotBridgeReturn".to_string(),
                        expression: BridgeExpression::Binding { ghost_mass: None,  name: return_binding },
                        source_location: None,
                    };
                    state.node_plans.push(ret_plan.clone());
                    state.operations.push(BridgeOperation::Return { plan: ret_plan });
                    return Ok(());
                }

                let ret_node_id = state.create_node_id("return", "result");
                let ret_plan = BridgeNodePlan::Return { ghost_mass: None, 
                    node_id: ret_node_id,
                    handler_label: "PolyglotBridgeReturn".to_string(),
                    expression: compile_polyglot_expression(expr)?,
                    source_location: None,
                };
                state.node_plans.push(ret_plan.clone());
                state.operations.push(BridgeOperation::Return { plan: ret_plan });
            } else {
                let ret_node_id = state.create_node_id("return", "void");
                let ret_plan = BridgeNodePlan::Return { ghost_mass: None, 
                    node_id: ret_node_id,
                    handler_label: "PolyglotBridgeReturn".to_string(),
                    expression: BridgeExpression::Literal { ghost_mass: None,  value: serde_json::Value::Null },
                    source_location: None,
                };
                state.node_plans.push(ret_plan.clone());
                state.operations.push(BridgeOperation::Return { plan: ret_plan });
            }
            Ok(())
        }
        PolyglotStatement::Expression(expr) => {
            if let PolyglotExpression::Call { callee, args } = expr {
                let callee_expr = compile_polyglot_expression(callee)?;
                let mut compiled_args = Vec::new();
                for arg in args {
                    compiled_args.push(compile_polyglot_expression(arg)?);
                }

                let node_id = state.create_node_id("call", "effect");
                let plan = BridgeNodePlan::Call { ghost_mass: None, 
                    node_id,
                    handler_label: "PolyglotBridgeCall".to_string(),
                    callee: callee_expr,
                    this_arg: None,
                    args: compiled_args,
                    assign_to: None,
                    source_location: None,
                };
                state.operations.push(BridgeOperation::Call { plan });
                Ok(())
            } else {
                Err("Unsupported standalone expression in polyglot statement".to_string())
            }
        }
    }
}

pub fn compile_polyglot_function(
    func: &PolyglotFunction,
    state: &mut CompileState,
) -> Result<(), String> {
    for stmt in &func.body {
        compile_polyglot_statement(stmt, state)?;
    }
    
    if state.operations.is_empty() {
        let ret_node_id = state.create_node_id("return", "void");
        let ret_plan = BridgeNodePlan::Return { ghost_mass: None, 
            node_id: ret_node_id.clone(),
            handler_label: "PolyglotBridgeReturn".to_string(),
            expression: BridgeExpression::Literal { ghost_mass: None,  value: serde_json::Value::Null },
            source_location: None,
        };
        state.node_plans.push(ret_plan.clone());
        state.operations.push(BridgeOperation::Return { plan: ret_plan });
    }
    
    Ok(())
}
